function computeSequence(n, memo = {}) {
  if (n <= 1) return [n];
  if (memo[n]) return memo[n];

  const prev = computeSequence(n - 1, memo);
  const transformed = prev.map(x => x * n);
  const sum = transformed.reduce((acc, val) => acc + val, 0);

  memo[n] = [...prev, sum];
  return memo[n];
}

