int sumUpTo(int n) {
    int sum = 0;
    for (int i = 1; i < n; ++i) {
        sum += i;
    }
    return sum;
}

def merge_dicts(d1, d2):
    for k, v in d2.items():
        if k in d1:
            if isinstance(d1[k], dict) and isinstance(v, dict):
                merge_dicts(d1[k], v)
            else:
                d1[k] = v
        else:
            d1[k] = v
    return d1


